        expect(px(menu.style.left)).toBe(137);
        expect(px(menu.style.top)).toBe(242);
        // And they coincide with the clamp formula (a no-op here).
        expect(px(menu.style.left)).toBe(expectedClampX(menu, 137));
        expect(px(menu.style.top)).toBe(expectedClampY(menu, 242));
      });

