        const menu = menuOf(actionsOf(results, 'a.txt'));

        openViaContext(row, 99999, 200);

        expect(px(menu.style.left)).toBe(expectedClampX(menu, 99999));
        // y was comfortably inside → left untouched.
        expect(px(menu.style.top)).toBe(200);
      });

      it('clamps only the overflowing axis: y past the bottom edge, x within bounds', async () => {
        const { results } = await setupCleared();
        renderBrowse(browseResult({ path: 'docs', entries: [file] }));
        const row = rowByName(results.querySelector('table')!, 'a.txt')!;
        const menu = menuOf(actionsOf(results, 'a.txt'));

        openViaContext(row, 200, 99999);

        // x was comfortably inside → left untouched.
        expect(px(menu.style.left)).toBe(200);
        expect(px(menu.style.top)).toBe(expectedClampY(menu, 99999));
      });

      it('keeps the menu within the viewport for a range of edge coordinates', async () => {
        const { results } = await setupCleared();
        renderBrowse(browseResult({ path: 'docs', entries: [file] }));
        const row = rowByName(results.querySelector('table')!, 'a.txt')!;
        const menu = menuOf(actionsOf(results, 'a.txt'));

        const cases: Array<[number, number]> = [
          [0, 0],
          [window.innerWidth, window.innerHeight],
          [window.innerWidth + 1000, window.innerHeight + 1000],
          [-10, -10],
          [window.innerWidth - 1, 50],
          [50, window.innerHeight - 1],
        ];
        for (const [x, y] of cases) {
          openViaContext(row, x, y);
          const left = px(menu.style.left);
          const top = px(menu.style.top);
          const rect = menu.getBoundingClientRect();
          // Invariant: the whole menu box stays in [4, innerWidth] x [4, innerHeight].
          expect(left).toBeGreaterThanOrEqual(4);
          expect(top).toBeGreaterThanOrEqual(4);
          expect(left + rect.width).toBeLessThanOrEqual(window.innerWidth);
          expect(top + rect.height).toBeLessThanOrEqual(window.innerHeight);
          // And the position matches the documented clamp formula.
          expect(left).toBe(expectedClampX(menu, x));
          expect(top).toBe(expectedClampY(menu, y));
